import { TypeQuizQuestion } from "./quiz-types";
export const newQType4: TypeQuizQuestion[] = [
  // ── DIFFICULTY 1 (20 questions) ──
  { id: 751, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Real-Life Scenarios", question: "A Type 4 walks into a party where everyone seems to be having a great time. Their first instinct is:", options: [{ letter: "A", text: "Jump right in and join the fun" }, { letter: "B", text: "Feel like an outsider watching through glass — everyone else seems to belong naturally in a way they never can" }, { letter: "C", text: "Immediately start organizing the event" }, { letter: "D", text: "Find the most important person to network with" }], answer: "B", explanation: "Fours experience a fundamental sense of being different from others. Even at a fun event, their attention goes to the gap between themselves and others, reinforcing the feeling that something essential is missing in them." },
  { id: 752, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Real-Life Scenarios", question: "A Type 4 receives the same birthday gift as their sibling. How do they feel?", options: [{ letter: "A", text: "Happy — great minds think alike!" }, { letter: "B", text: "Deflated — being given the same gift means the giver didn't see what makes them unique" }, { letter: "C", text: "Relieved — at least it's a fair approach" }, { letter: "D", text: "Indifferent — a gift is a gift" }], answer: "B", explanation: "For Fours, being treated the same as others feels like not being seen. Their identity is built on being unique, so identical treatment registers as erasure of their individuality." },
  { id: 753, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Emotional Reactions", question: "When a Type 4 feels happy, they often:", options: [{ letter: "A", text: "Enjoy it fully without complication" }, { letter: "B", text: "Feel a bittersweet undertow — happiness tinged with the awareness that it will end, or a sense that they don't deserve it" }, { letter: "C", text: "Immediately share it with everyone" }, { letter: "D", text: "Get suspicious that something bad will happen" }], answer: "B", explanation: "Fours have a complicated relationship with positive emotions. Happiness can feel foreign, fragile, or even threatening to their identity as someone who feels deeply. The melancholy undertow is their emotional home frequency." },
  { id: 754, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Emotional Reactions", question: "When someone tells a Four 'You're overreacting,' the Four typically feels:", options: [{ letter: "A", text: "Grateful for the reality check" }, { letter: "B", text: "Deeply misunderstood — as if their entire inner world has been dismissed" }, { letter: "C", text: "Amused" }, { letter: "D", text: "Motivated to tone it down" }], answer: "B", explanation: "Being told they're overreacting is one of the most painful things for a Four. Their emotional intensity is their identity — dismissing it feels like dismissing their very existence. They feel unseen in the deepest way." },
  { id: 755, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Type in Pop Culture", question: "Which fictional character best exemplifies Type 4's sense of being fundamentally different and the longing for what's missing?", options: [{ letter: "A", text: "Thor from Marvel" }, { letter: "B", text: "Elio from Call Me By Your Name" }, { letter: "C", text: "Ron Weasley from Harry Potter" }, { letter: "D", text: "Sherlock Holmes" }], answer: "B", explanation: "Elio embodies Four energy: the intense internal emotional landscape, aesthetic sensitivity, romanticizing of loss, longing for the absent beloved, and the sense that the most real feelings are also the most painful." },
  { id: 756, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Type in Pop Culture", question: "Which musician most represents the Type 4 pattern of transforming personal pain into art?", options: [{ letter: "A", text: "Ed Sheeran" }, { letter: "B", text: "Elliott Smith" }, { letter: "C", text: "Pharrell Williams" }, { letter: "D", text: "Bruno Mars" }], answer: "B", explanation: "Elliott Smith's music is a masterclass in Four energy: deeply personal lyrics, melancholic beauty, unflinching emotional honesty, and the sense that suffering itself is a form of authenticity. He transmuted pain into haunting art." },
  { id: 757, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Quick Identification", question: "Which phrase is most characteristic of a Type 4?", options: [{ letter: "A", text: "Let's keep things moving and stay on schedule" }, { letter: "B", text: "Nobody really understands what I'm going through" }, { letter: "C", text: "What's the most logical approach?" }, { letter: "D", text: "How can I help everyone feel included?" }], answer: "B", explanation: "This sentiment captures the Four's core experience: a fundamental belief in the uniqueness and depth of their suffering. It's not self-pity — it's a genuine perception that their inner world is too complex for others to fully grasp." },
  { id: 758, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Quick Identification", question: "Which aesthetic choice most suggests someone is a Type 4?", options: [{ letter: "A", text: "Matching their outfit to current trends" }, { letter: "B", text: "Curating a distinctive personal style that sets them apart — vintage, artistic, or deliberately unconventional" }, { letter: "C", text: "Wearing practical, no-fuss clothing" }, { letter: "D", text: "Always dressing in professional attire" }], answer: "B", explanation: "Fours express their identity through aesthetics. Their style isn't about fitting in or impressing — it's about expressing their inner world externally. Each choice says: 'I'm not like everyone else, and my appearance should reflect that.'" },
  { id: 759, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Common Phrases", question: "Which internal monologue is most typical for a Type 4?", options: [{ letter: "A", text: "How can I be more efficient?" }, { letter: "B", text: "What is missing from my life? Why do others seem to have something I don't?" }, { letter: "C", text: "Is everyone getting along?" }, { letter: "D", text: "What do people need from me?" }], answer: "B", explanation: "The Four's attention habitually goes to what's absent rather than what's present. They scan for the missing piece — the experience they haven't had, the love they don't have, the quality others possess that they lack." },
  { id: 760, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Common Phrases", question: "A Four listening to music is most likely to:", options: [{ letter: "A", text: "Choose upbeat songs to boost their mood" }, { letter: "B", text: "Seek out songs that match and amplify their current emotional state — even if that state is melancholy" }, { letter: "C", text: "Play whatever's on the radio" }, { letter: "D", text: "Analyze the technical composition" }], answer: "B", explanation: "Fours use music as an emotional amplifier, not a mood corrector. If they're sad, they play sad music — not to wallow, but because matching the emotion externally feels like being truly understood. The sadness becomes beautiful." },
  { id: 761, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 11, track2Day: 61, category: "Childhood Patterns", question: "What childhood experience is most formative for Type 4s?", options: [{ letter: "A", text: "Being constantly praised and celebrated" }, { letter: "B", text: "Feeling fundamentally different from their family — like they were left on the wrong doorstep or that something essential was missing in the parent-child bond" }, { letter: "C", text: "Being given excessive responsibility" }, { letter: "D", text: "Having strict rules and structure" }], answer: "B", explanation: "Fours often describe childhood as feeling like an alien in their own family. Whether through actual loss, emotional disconnection, or temperamental mismatch, they developed the sense that they were fundamentally different — and that difference meant deficiency." },
  { id: 762, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 12, track2Day: 62, category: "Childhood Patterns", question: "As children, Type 4s often:", options: [{ letter: "A", text: "Were the most popular kid in school" }, { letter: "B", text: "Created rich imaginary worlds, wrote poetry, or expressed complex emotions that surprised adults" }, { letter: "C", text: "Focused on athletic achievement" }, { letter: "D", text: "Were class presidents and organizers" }], answer: "B", explanation: "Young Fours channel their sense of being different into creative self-expression. Art, writing, and imagination become ways to process their intense inner world and give form to feelings that don't fit the ordinary childhood experience." },
  { id: 763, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 13, track2Day: 63, category: "Communication Style", question: "How does a Type 4 typically share good news?", options: [{ letter: "A", text: "With straightforward excitement" }, { letter: "B", text: "With complexity — qualifying it, noting what's still missing, or finding the bittersweet angle" }, { letter: "C", text: "By downplaying it entirely" }, { letter: "D", text: "By broadcasting it to everyone immediately" }], answer: "B", explanation: "Fours struggle with uncomplicated positivity. Good news gets processed through their emotional complexity filter: 'I got the job, but I'm not sure it's the right one,' or 'It's great, but I can't help feeling like something's off.'" },
  { id: 764, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 14, track2Day: 64, category: "Communication Style", question: "In conversations, a Type 4 tends to:", options: [{ letter: "A", text: "Keep things surface-level and light" }, { letter: "B", text: "Steer toward emotional depth and authenticity — they get impatient with small talk and want to get 'real'" }, { letter: "C", text: "Dominate with their opinions" }, { letter: "D", text: "Listen quietly without contributing" }], answer: "B", explanation: "Fours crave emotional truth in connection. Small talk feels like a waste of their time and an insult to the conversation's potential. They want to skip to the meaningful part where people reveal who they really are." },
  { id: 765, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 15, track2Day: 65, category: "Real-Life Scenarios", question: "A Type 4 visits a beautiful tourist destination that's crowded with other tourists. They feel:", options: [{ letter: "A", text: "Excited to share the experience with so many people" }, { letter: "B", text: "Disappointed that the experience isn't unique — the magic is ruined by the ordinariness of mass tourism" }, { letter: "C", text: "Happy to follow the guided tour" }, { letter: "D", text: "Focused on getting the best photos for social media" }], answer: "B", explanation: "Fours need experiences to feel personal and unique. When something beautiful becomes commonplace, it loses its meaning. They'd rather find a hidden waterfall no one knows about than visit the famous one everyone's already Instagrammed." },
  { id: 766, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 16, track2Day: 66, category: "Emotional Reactions", question: "When a Type 4 sees someone else expressing 'their' aesthetic or style, they feel:", options: [{ letter: "A", text: "Flattered that others share their taste" }, { letter: "B", text: "A territorial sting — as if their uniqueness has been stolen or diluted" }, { letter: "C", text: "Completely indifferent" }, { letter: "D", text: "Happy to belong to a like-minded community" }], answer: "B", explanation: "Fours derive identity from being unique. When someone mirrors their style, it threatens their distinctiveness. This can trigger the envy pattern: 'They stole my thing,' followed by a compulsion to differentiate further." },
  { id: 767, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 17, track2Day: 67, category: "Quick Identification", question: "Which social media behavior most suggests a Four?", options: [{ letter: "A", text: "Posting motivational quotes and success stories" }, { letter: "B", text: "Curating a moody, aesthetic feed with cryptic captions that hint at deep feelings without fully explaining them" }, { letter: "C", text: "Sharing practical tips and how-to content" }, { letter: "D", text: "Posting frequently about group activities" }], answer: "B", explanation: "Fours use social media as art gallery rather than billboard. Their posts are carefully curated emotional expressions — they want to be understood but not fully explained, creating mystique through aesthetic vulnerability." },
  { id: 768, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 18, track2Day: 68, category: "Common Phrases", question: "Which statement most reveals the Four's relationship with longing?", options: [{ letter: "A", text: "I have everything I need" }, { letter: "B", text: "I feel like the best version of my life is somewhere else — the job I didn't take, the person I didn't meet, the place I haven't been" }, { letter: "C", text: "I'm content with what I have" }, { letter: "D", text: "I don't think about what could have been" }], answer: "B", explanation: "Longing is the Four's emotional signature. They are perpetually oriented toward what's absent, creating a sweet ache for the life they're not living. The fantasy of 'elsewhere' feels more real and vibrant than the ordinary present." },
  { id: 769, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 19, track2Day: 69, category: "Childhood Patterns", question: "Type 4 children often had a relationship with a parent that felt:", options: [{ letter: "A", text: "Perfectly secure and uncomplicated" }, { letter: "B", text: "Marked by a sense of abandonment or disconnection — the parent was there but somehow emotionally unreachable" }, { letter: "C", text: "Strictly disciplinary" }, { letter: "D", text: "Overly enmeshed and codependent" }], answer: "B", explanation: "The Four's wound often involves a parent who was present but not emotionally attuned. This creates the foundational Four experience: something essential is missing, and it was taken away before I could name it." },
  { id: 770, type: 4, difficulty: 1 as 1|2|3|4|5, track1Day: 20, track2Day: 70, category: "Communication Style", question: "A Type 4's journal entries typically feature:", options: [{ letter: "A", text: "Bullet-pointed to-do lists" }, { letter: "B", text: "Richly descriptive emotional explorations with poetic language and intense self-analysis" }, { letter: "C", text: "Brief factual summaries of the day" }, { letter: "D", text: "Mostly blank pages" }], answer: "B", explanation: "Fours journal like artists: their entries are deep dives into emotional terrain, often with beautiful language and raw honesty. The journal is where the Four feels most themselves — free to explore without the performance of normalcy." },
  // ── DIFFICULTY 2 (20 questions) ──
  { id: 771, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 21, track2Day: 71, category: "Relationship Dynamics", question: "In romantic relationships, Type 4s are most at risk of:", options: [{ letter: "A", text: "Being too practical and unromantic" }, { letter: "B", text: "The push-pull pattern: intensely pursuing someone unavailable, then losing interest once the person is fully present" }, { letter: "C", text: "Being too independent and detached" }, { letter: "D", text: "Settling too easily" }], answer: "B", explanation: "Fours are drawn to longing itself. When someone is unavailable, desire intensifies. When they become available, the Four may feel: 'This can't be it.' The ordinary reality of a present partner can't compete with the intensity of yearning for an absent one." },
  { id: 772, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 22, track2Day: 72, category: "Relationship Dynamics", question: "The Four-Nine pairing is common because:", options: [{ letter: "A", text: "They have identical personalities" }, { letter: "B", text: "The Nine's calm steadiness grounds the Four's emotional storms, while the Four adds depth and intensity the Nine secretly craves but won't access alone" }, { letter: "C", text: "They're both highly ambitious" }, { letter: "D", text: "It's random chance" }], answer: "B", explanation: "Fours and Nines complement each other's gaps: the Four brings emotional intensity the Nine has suppressed, and the Nine provides the steady, accepting presence the Four desperately needs but can't give themselves." },
  { id: 773, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 23, track2Day: 73, category: "Defense Mechanisms", question: "What is the primary defense mechanism of Type 4?", options: [{ letter: "A", text: "Denial" }, { letter: "B", text: "Introjection — taking in and identifying with negative self-images and painful experiences as core to who they are" }, { letter: "C", text: "Reaction formation" }, { letter: "D", text: "Sublimation" }], answer: "B", explanation: "Introjection means the Four absorbs negative experiences as identity. Where others might externalize ('That was a bad situation'), Fours internalize ('I am fundamentally flawed'). Pain becomes not something that happened TO them but something that IS them." },
  { id: 774, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 24, track2Day: 74, category: "Defense Mechanisms", question: "How does the Four's envy operate as a fixation?", options: [{ letter: "A", text: "They want others' material possessions" }, { letter: "B", text: "They perceive others as possessing an essential quality of normalcy, belonging, or wholeness that they lack — and this perception organizes their entire worldview" }, { letter: "C", text: "They're competitive about achievements" }, { letter: "D", text: "They don't experience envy" }], answer: "B", explanation: "Four's envy isn't about wanting someone's car or job — it's existential. They perceive others as having an innate wholeness or ease of being that was withheld from them. This isn't a passing feeling; it's the lens through which they see the world." },
  { id: 775, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 25, track2Day: 75, category: "Conflict Style", question: "How does a Type 4 typically initiate conflict?", options: [{ letter: "A", text: "With logical arguments" }, { letter: "B", text: "Through emotional intensity — expressing hurt feelings with dramatic force, making others feel the depth of their pain" }, { letter: "C", text: "With passive-aggressive hints" }, { letter: "D", text: "They never initiate conflict" }], answer: "B", explanation: "Fours fight with emotional truth as their weapon. They express their pain with such intensity and specificity that it can overwhelm others. Their goal isn't to win the argument but to make you understand the depth of their experience." },
  { id: 776, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 26, track2Day: 76, category: "Conflict Style", question: "After a conflict, a Type 4 often:", options: [{ letter: "A", text: "Moves on quickly" }, { letter: "B", text: "Replays the argument internally for days, deepening the emotional wound and crafting what they wish they'd said" }, { letter: "C", text: "Pretends it never happened" }, { letter: "D", text: "Seeks revenge" }], answer: "B", explanation: "Fours metabolize conflict slowly and intensely. They replay scenes, adding emotional depth and narrative weight. The argument becomes a story about their fundamental aloneness, and the perfect comeback arrives days too late." },
  { id: 777, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 27, track2Day: 77, category: "Shadow Work", question: "What is the Four's deepest fear?", options: [{ letter: "A", text: "Being controlled" }, { letter: "B", text: "Having no identity or personal significance — being ordinary, interchangeable, without unique meaning" }, { letter: "C", text: "Being unsafe" }, { letter: "D", text: "Being unproductive" }], answer: "B", explanation: "The Four's existential terror is ordinariness. If they're not unique, they're nothing. This fear drives both their creative expression and their suffering — they'd rather be tragically special than comfortably normal." },
  { id: 778, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 28, track2Day: 78, category: "Shadow Work", question: "The Four's 'specialness through suffering' pattern means:", options: [{ letter: "A", text: "They enjoy pain" }, { letter: "B", text: "They unconsciously maintain suffering because it confirms their uniqueness — ordinary people have ordinary problems, but their pain is exceptional" }, { letter: "C", text: "They're physically tough" }, { letter: "D", text: "They help others through suffering" }], answer: "B", explanation: "Fours can unconsciously sabotage happiness because ordinariness threatens their identity. If their pain is extraordinary, so are they. Healing means giving up the story that their suffering makes them special — terrifying for a type built on being different." },
  { id: 779, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 29, track2Day: 79, category: "Parenting Style", question: "Type 4 parents are most likely to:", options: [{ letter: "A", text: "Follow strict parenting manuals" }, { letter: "B", text: "Encourage their children's creative self-expression while occasionally burdening them with too much emotional intensity" }, { letter: "C", text: "Be completely hands-off" }, { letter: "D", text: "Focus primarily on academic achievement" }], answer: "B", explanation: "Four parents gift their children with emotional permission — 'Feel everything, express everything.' But they can also unconsciously recruit children into their emotional world, making the child feel responsible for the parent's inner weather." },
  { id: 780, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 30, track2Day: 80, category: "Attachment Style", question: "Which attachment style is most common among Type 4s?", options: [{ letter: "A", text: "Secure" }, { letter: "B", text: "Anxious-preoccupied or fearful-avoidant — the push-pull of desperately wanting connection while fearing they'll be abandoned once truly known" }, { letter: "C", text: "Dismissive-avoidant" }, { letter: "D", text: "No attachment pattern" }], answer: "B", explanation: "Fours often oscillate between anxious clinging and avoidant withdrawal. They desperately want intimacy but fear that being truly known will confirm their worst suspicion: that they're fundamentally defective and will be abandoned." },
  { id: 781, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 31, track2Day: 81, category: "Somatic Patterns", question: "Where do Type 4s most commonly hold emotional pain in their body?", options: [{ letter: "A", text: "Their head and forehead" }, { letter: "B", text: "Their chest and heart area — often describing a literal ache, heaviness, or hollowness in the center of their being" }, { letter: "C", text: "Their lower back" }, { letter: "D", text: "Their shoulders" }], answer: "B", explanation: "As a Heart center type, Fours experience emotions somatically in the chest. They describe their heart as a cavern: sometimes achingly full, sometimes hollowly empty. Heartbreak isn't metaphorical for Fours — they feel it physically." },
  { id: 782, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 32, track2Day: 82, category: "Somatic Patterns", question: "Fours in depression often describe the experience as:", options: [{ letter: "A", text: "Simple sadness" }, { letter: "B", text: "A familiar home — dark but known, with a strange comfort in the depth of feeling, as if depression confirms the reality of their inner world" }, { letter: "C", text: "Pure numbness" }, { letter: "D", text: "Irritability and anger" }], answer: "B", explanation: "Fours have an ambivalent relationship with depression: it's painful but familiar. The depth of feeling confirms they're alive and real. This makes recovery complicated — getting better can feel like losing something authentic about themselves." },
  { id: 783, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 33, track2Day: 83, category: "Coping Under Stress", question: "When stressed, Type 4s move toward which type's behaviors?", options: [{ letter: "A", text: "Type 7 — becoming scattered, manic, and seeking distraction" }, { letter: "B", text: "Type 2 — becoming clingy, people-pleasing, and over-involved in others' lives to escape their own pain" }, { letter: "C", text: "Type 8 — becoming aggressive and controlling" }, { letter: "D", text: "Type 5 — withdrawing completely" }], answer: "B", explanation: "Under stress, Fours disintegrate to Two: the self-focused individualist becomes needy and other-focused. They seek external validation, become clingy, and may try to earn love through helpfulness — abandoning their independence for connection." },
  { id: 784, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 34, track2Day: 84, category: "Coping Under Stress", question: "What does healthy growth look like for a Type 4?", options: [{ letter: "A", text: "Becoming more emotionally intense" }, { letter: "B", text: "Moving toward Type 1 qualities: disciplined action, objective standards, and engaging with reality rather than just feeling about it" }, { letter: "C", text: "Withdrawing further into their inner world" }, { letter: "D", text: "Becoming more competitive" }], answer: "B", explanation: "In growth, Fours integrate to One: they add discipline to their creativity, action to their feelings, and objective standards to their subjective world. They stop just feeling and start doing — transforming emotional insight into principled action." },
  { id: 785, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 35, track2Day: 85, category: "Workplace Archetypes", question: "Which workplace role does a Type 4 most naturally gravitate toward?", options: [{ letter: "A", text: "Data analyst" }, { letter: "B", text: "Creative roles where personal expression is valued — designer, writer, therapist, or artist" }, { letter: "C", text: "Project manager" }, { letter: "D", text: "Corporate strategist" }], answer: "B", explanation: "Fours seek work that allows personal expression and emotional depth. They thrive when their unique perspective is valued and wither in roles that demand conformity. The work itself must feel meaningful and authentic." },
  { id: 786, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 36, track2Day: 86, category: "Workplace Archetypes", question: "A Type 4's biggest workplace challenge is:", options: [{ letter: "A", text: "Lack of creativity" }, { letter: "B", text: "Emotional reactivity and taking feedback personally — difficulty separating critique of their work from critique of their identity" }, { letter: "C", text: "Being too agreeable" }, { letter: "D", text: "Working too fast" }], answer: "B", explanation: "Because Fours pour their identity into their work, criticism of the work feels like criticism of their soul. 'This design needs revision' registers as 'You are inadequate.' Separating craft from identity is their professional growth edge." },
  { id: 787, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 37, track2Day: 87, category: "Relationship Dynamics", question: "What makes Type 4s exceptional partners when they're healthy?", options: [{ letter: "A", text: "Their efficiency" }, { letter: "B", text: "Their capacity for profound emotional intimacy — they can sit with pain, see the full spectrum of human experience, and make their partner feel deeply known" }, { letter: "C", text: "Their practicality" }, { letter: "D", text: "Their social connections" }], answer: "B", explanation: "At their best, Fours are unparalleled in emotional depth. They don't flinch from darkness, they see beauty in brokenness, and they make their partners feel truly seen. No other type can hold emotional space with such unflinching presence." },
  { id: 788, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 38, track2Day: 88, category: "Defense Mechanisms", question: "The Four's 'emotional amplification' pattern serves to:", options: [{ letter: "A", text: "Help them communicate better" }, { letter: "B", text: "Maintain the intensity that confirms their unique identity — if their feelings are the strongest, their selfhood is the most real" }, { letter: "C", text: "Manipulate others" }, { letter: "D", text: "Protect them from physical danger" }], answer: "B", explanation: "Fours amplify emotions because intensity = identity. If their feelings are deeper, more nuanced, more painful than others', they are more real, more alive, more themselves. Emotional amplification is an identity-maintenance strategy." },
  { id: 789, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 39, track2Day: 89, category: "Shadow Work", question: "The Four's 'disdain for the ordinary' conceals:", options: [{ letter: "A", text: "Genuine superiority" }, { letter: "B", text: "A deep longing to feel at ease in the ordinary world — their disdain is a defense against the pain of wanting to belong but feeling unable to" }, { letter: "C", text: "Laziness" }, { letter: "D", text: "Practical concerns" }], answer: "B", explanation: "When Fours look down on 'basic' people, they're defending against envy. The disdain covers the wound: 'I wish I could be happy with simple things, but something in me won't allow it.' Superiority masks longing." },
  { id: 790, type: 4, difficulty: 2 as 1|2|3|4|5, track1Day: 40, track2Day: 90, category: "Childhood Patterns", question: "The Four child's relationship with the idealized absent parent figure creates:", options: [{ letter: "A", text: "Healthy attachment" }, { letter: "B", text: "A lifelong pattern of romanticizing what's absent — the missing parent becomes the template for all future longing" }, { letter: "C", text: "Independence" }, { letter: "D", text: "Fear of authority" }], answer: "B", explanation: "The Four's original wound — the lost or emotionally unavailable parent — becomes a template. They continue seeking the absent beloved in romantic partners, idealized careers, and imagined alternative lives. The longing itself becomes home." },
  // ── DIFFICULTY 3 (20 questions) ──
  { id: 791, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Spiritual Traditions", question: "In contemplative traditions, the Four's growth path often involves:", options: [{ letter: "A", text: "More emotional expression" }, { letter: "B", text: "Practices of equanimity — learning that all emotions are passing weather, not permanent identity, and that the ordinary moment is as sacred as the intense one" }, { letter: "C", text: "Intellectual study" }, { letter: "D", text: "Competitive spiritual achievement" }], answer: "B", explanation: "Fours need equanimity practices that teach them emotions are weather, not climate. The ordinary Tuesday afternoon is as real and sacred as the dramatic heartbreak. Presence in the mundane is the Four's ultimate spiritual challenge." },
  { id: 792, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Spiritual Traditions", question: "The Sufi concept of 'fana' (annihilation of the ego) challenges the Four because:", options: [{ letter: "A", text: "They love ego dissolution" }, { letter: "B", text: "Their entire identity is built on being uniquely themselves — dissolving the self feels like losing the only thing they have" }, { letter: "C", text: "They're already egoless" }, { letter: "D", text: "They prefer Buddhism" }], answer: "B", explanation: "Fana asks the Four to let go of the very thing they've constructed their life around: their unique, special self. For other types, this is hard. For Fours, it's a direct confrontation with their deepest fear — nonexistence through ordinariness." },
  { id: 793, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Enneagram x MBTI", question: "How does a Type 4 INFP differ from a Type 4 ISFP?", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "The INFP Four lives more in imagination, narrative, and symbolic meaning; the ISFP Four lives more in sensory aesthetics, physical expression, and present-moment experience" }, { letter: "C", text: "ISFPs can't be Fours" }, { letter: "D", text: "INFPs are less emotional" }], answer: "B", explanation: "Both share the Four's emotional depth, but they access it differently. INFP Fours create internal narrative worlds of meaning. ISFP Fours express through physical mediums: visual art, dance, fashion, and direct sensory experience." },
  { id: 794, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Enneagram x MBTI", question: "A Type 4 ENTJ is an unusual combination because:", options: [{ letter: "A", text: "It doesn't exist" }, { letter: "B", text: "The Four's emotional depth and identity-seeking meets the ENTJ's strategic, results-oriented drive — creating someone who channels intense feelings into ambitious creative or entrepreneurial visions" }, { letter: "C", text: "All Fours are introverts" }, { letter: "D", text: "ENTJs don't have feelings" }], answer: "B", explanation: "The 4-ENTJ combines unusual elements: deep feelings with strategic action. These rare individuals might be intense creative directors, visionary entrepreneurs, or leaders who bring emotional intelligence to high-powered roles." },
  { id: 795, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Instinct x Wing Combos", question: "How does a Self-Preservation 4 (SP4) differ from the stereotypical Four?", options: [{ letter: "A", text: "They're identical to the stereotype" }, { letter: "B", text: "SP4s are the counter-type — they internalize suffering rather than expressing it, endure pain stoically, and may look like Ones or Fives rather than dramatic, expressive Fours" }, { letter: "C", text: "SP4s are the most dramatic" }, { letter: "D", text: "SP4s don't feel emotions" }], answer: "B", explanation: "SP4 is the counter-type Four: they suffer intensely but silently. Instead of expressing emotional drama, they endure it — 'tenacity through suffering.' They look stoic, hardworking, and tough, often mistyped as Ones because their envy is masked by endurance." },
  { id: 796, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Instinct x Wing Combos", question: "A Sexual (SX) Four is characterized by:", options: [{ letter: "A", text: "Quiet introspection" }, { letter: "B", text: "Intense, competitive envy expressed outwardly — they don't just feel inferior, they may become demanding, angry, and vocal about what they deserve" }, { letter: "C", text: "Social conformity" }, { letter: "D", text: "Emotional detachment" }], answer: "B", explanation: "SX Fours are the most externally intense. Their envy becomes competition and demand: 'I deserve what they have.' They can look like Eights in their forcefulness. This is the Four subtype most likely to express anger directly rather than internalizing it." },
  { id: 797, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Tritype Deep Dives", question: "The 458 tritype ('The Scholar') combines:", options: [{ letter: "A", text: "Three random types" }, { letter: "B", text: "The Four's depth and authenticity with the Five's analytical mind and the Eight's forcefulness — creating an intense, private, deeply knowledgeable person who demands truth" }, { letter: "C", text: "The most cheerful types" }, { letter: "D", text: "The most social types" }], answer: "B", explanation: "The 458 is one of the most intense tritypes: emotionally deep (4), intellectually penetrating (5), and forcefully honest (8). They demand authenticity with an almost aggressive edge and have zero tolerance for surface-level anything." },
  { id: 798, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Tritype Deep Dives", question: "How does a 469 tritype differ from a 478 tritype?", options: [{ letter: "A", text: "They're the same" }, { letter: "B", text: "The 469 is anxious, self-doubting, and seeks comfort through connection; the 478 is more assertive, rebellious, and channels emotional energy into bold creative or intellectual pursuits" }, { letter: "C", text: "469 is more aggressive" }, { letter: "D", text: "478 is more passive" }], answer: "B", explanation: "Same core type (4), vastly different expressions. The 469 adds Six's anxiety and Nine's merging, creating a more tentative, approval-seeking Four. The 478 adds Seven's expansiveness and Eight's power, creating a forceful, expressive Four who demands space." },
  { id: 799, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Growth Practices", question: "Why is routine and discipline particularly transformative for Type 4s?", options: [{ letter: "A", text: "They naturally love routine" }, { letter: "B", text: "It teaches them that showing up regardless of mood builds something real — that reliable action, not emotional intensity, creates the meaningful life they long for" }, { letter: "C", text: "It makes them more interesting" }, { letter: "D", text: "It distracts from feelings" }], answer: "B", explanation: "Fours wait for inspiration, acting only when the mood strikes. Discipline — writing daily whether inspired or not, exercising even when sad — teaches them that the ordinary, reliable action creates the extraordinary life, not waiting for the perfect emotional state." },
  { id: 800, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Growth Practices", question: "The practice of 'gratitude without qualification' challenges Fours because:", options: [{ letter: "A", text: "They're already grateful" }, { letter: "B", text: "Their habit is to qualify every positive ('I'm grateful, BUT...') — pure gratitude without the melancholic qualifier feels like betraying their emotional depth" }, { letter: "C", text: "They don't understand gratitude" }, { letter: "D", text: "It's too simple" }], answer: "B", explanation: "Ask a Four to say 'I'm grateful for my life' without adding 'but it could be better' or 'though something's missing.' Pure, uncomplicated gratitude challenges the Four's entire emotional operating system, which runs on longing." },
  { id: 801, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Naranjo's Character Types", question: "Claudio Naranjo described the Four's character as:", options: [{ letter: "A", text: "The Achiever" }, { letter: "B", text: "The 'self-frustrating' personality — someone who unconsciously sabotages their own happiness to maintain the intensity and depth of their suffering" }, { letter: "C", text: "The Reformer" }, { letter: "D", text: "The Helper" }], answer: "B", explanation: "Naranjo saw the Four's pattern as fundamentally self-defeating: they desire happiness but unconsciously create the conditions for suffering because suffering is identity-confirming. The goal (happiness) would threaten the structure (unique suffering)." },
  { id: 802, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Naranjo's Character Types", question: "Naranjo linked the Four to which of Freud's character types?", options: [{ letter: "A", text: "Oral character" }, { letter: "B", text: "The masochistic character — not in the sexual sense, but as someone who unconsciously maintains pain as a way of feeling alive and significant" }, { letter: "C", text: "Anal character" }, { letter: "D", text: "Phallic character" }], answer: "B", explanation: "Naranjo connected the Four to the masochistic character structure: someone who derives identity from suffering, resists pleasure as if it would mean losing themselves, and maintains a relationship with pain that others find baffling." },
  { id: 803, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Panel Wisdom", question: "In Enneagram panels, Type 4s commonly report:", options: [{ letter: "A", text: "Always feeling confident" }, { letter: "B", text: "The shock of realizing that their suffering isn't unique — that other Fours feel the exact same 'nobody understands me' feeling, making their 'unique pain' universal" }, { letter: "C", text: "Having no emotional problems" }, { letter: "D", text: "Being indifferent to self-knowledge" }], answer: "B", explanation: "Panels are paradoxically healing for Fours: hearing other Fours describe the exact same 'nobody understands me' experience shatters the illusion of unique suffering. It's both devastating (my pain isn't special?) and liberating (I'm not alone in this)." },
  { id: 804, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Panel Wisdom", question: "What do advanced Four panelists say is the hardest part of growth?", options: [{ letter: "A", text: "Feeling more" }, { letter: "B", text: "Giving up the identity of being special through suffering — accepting ordinariness without it feeling like death" }, { letter: "C", text: "Working harder" }, { letter: "D", text: "Making more friends" }], answer: "B", explanation: "Mature Fours describe the terrifying moment of choosing ordinary happiness over extraordinary suffering. It feels like dying — the dramatic, special self dissolves into something simpler, quieter, and paradoxically more deeply authentic." },
  { id: 805, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Differential Diagnosis", question: "How do you distinguish a Type 4 from a Type 2?", options: [{ letter: "A", text: "Fours are always male, Twos female" }, { letter: "B", text: "Both are Heart types seeking identity through feeling, but Fours seek identity through being unique and deep, while Twos seek identity through being needed and connected — the Four individuates, the Two merges" }, { letter: "C", text: "They're the same type" }, { letter: "D", text: "Twos are more creative" }], answer: "B", explanation: "Both types are emotional and identity-focused, but with opposite strategies. Fours pull away to be special: 'I'm different from you.' Twos move toward to be valued: 'I'm essential to you.' One individuates through uniqueness; the other through service." },
  { id: 806, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Differential Diagnosis", question: "A person is creative, emotionally intense, and feels like an outsider. Could be a 4 or a 5. The differentiator is:", options: [{ letter: "A", text: "Intelligence level" }, { letter: "B", text: "Fours identify with their emotions and want others to see their depth; Fives detach from emotions and want to understand from a distance — the Four says 'feel with me,' the Five says 'let me think about this alone'" }, { letter: "C", text: "They're the same" }, { letter: "D", text: "Fives aren't creative" }], answer: "B", explanation: "Both are withdrawn and feel like outsiders, but for different reasons. Fours feel different and want to be seen in their depth. Fives feel different and want to be left alone with their thoughts. The Four leads with emotion; the Five leads with analysis." },
  { id: 807, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Workplace Archetypes", question: "A Four with a 3-wing (4w3) in creative work tends to:", options: [{ letter: "A", text: "Hide all their work" }, { letter: "B", text: "Combine authentic self-expression with a drive to be recognized for it — they want their art to be both meaningful AND successful" }, { letter: "C", text: "Focus only on commercial viability" }, { letter: "D", text: "Avoid creative work entirely" }], answer: "B", explanation: "The 4w3 adds ambition to authenticity. They don't just want to create — they want their creation to be seen, admired, and successful. This can create tension: 'Am I being authentic or just performing authenticity for an audience?'" },
  { id: 808, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Workplace Archetypes", question: "A Four with a 5-wing (4w5) in creative work tends to:", options: [{ letter: "A", text: "Be extremely social and collaborative" }, { letter: "B", text: "Create from a deep, private well of knowledge and emotion — their work is more cerebral, niche, and less concerned with audience approval" }, { letter: "C", text: "Copy others' styles" }, { letter: "D", text: "Focus on networking" }], answer: "B", explanation: "The 4w5 is the most withdrawn and intellectually deep Four variant. Their creativity draws from extensive knowledge and private emotional processing. They care less about recognition and more about the integrity and depth of the work itself." },
  { id: 809, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Communication Style", question: "The Four's tendency toward 'emotional storytelling' in conversation serves to:", options: [{ letter: "A", text: "Bore people" }, { letter: "B", text: "Create a shared emotional experience where the listener feels what the Four felt — turning communication into an empathic bridge" }, { letter: "C", text: "Avoid practical topics" }, { letter: "D", text: "Dominate the conversation" }], answer: "B", explanation: "When Fours tell stories, they're not just conveying information — they're creating an emotional experience. They want you to FEEL what happened, not just know it. This makes them compelling but sometimes exhausting communicators." },
  { id: 810, type: 4, difficulty: 3 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Coping Under Stress", question: "The Four's 'creative block' is often actually:", options: [{ letter: "A", text: "Lack of talent" }, { letter: "B", text: "An identity crisis — they can't create because they can't find the authentic emotional truth to express, and producing inauthentic work feels like self-betrayal" }, { letter: "C", text: "Laziness" }, { letter: "D", text: "Too many ideas" }], answer: "B", explanation: "Four's creative blocks are identity blocks. They can't make work that isn't authentically them, but they can't access what's authentically them. The block isn't about technique — it's about losing touch with the emotional wellspring that feeds their art." },
  // ── DIFFICULTY 4 (20 questions) ──
  { id: 811, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Ichazo Fixations", question: "Oscar Ichazo named the Four's fixation 'melancholy.' In his framework, this means:", options: [{ letter: "A", text: "Simple sadness" }, { letter: "B", text: "A cognitive habit of perceiving lack and deficiency everywhere — the mind automatically focuses on what's missing rather than what's present, creating a perpetual state of longing" }, { letter: "C", text: "Clinical depression" }, { letter: "D", text: "Nostalgia" }], answer: "B", explanation: "Ichazo's melancholy isn't a mood — it's a perceptual habit. The Four's mind is wired to notice absence: what's missing from this moment, this relationship, this life. This isn't chosen; it's the automatic filter through which reality is perceived." },
  { id: 812, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Ichazo Fixations", question: "The Four's holy idea in Ichazo's system is 'Holy Origin.' This means:", options: [{ letter: "A", text: "They should study their ancestry" }, { letter: "B", text: "The recognition that they are not separate from the source of being — what they seek through uniqueness and longing was never actually lost, because they were always connected to their origin" }, { letter: "C", text: "They should return to their hometown" }, { letter: "D", text: "They need to find their birth parents" }], answer: "B", explanation: "Holy Origin dissolves the Four's core belief: 'Something was taken from me.' The truth is that connection to the source was never severed — the Four's identity as 'the one who lost something' is itself the veil hiding what was always present." },
  { id: 813, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Object Relations Deep", question: "In object relations theory, the Four's developmental challenge relates to:", options: [{ letter: "A", text: "Too much mirroring" }, { letter: "B", text: "Inadequate mirroring of their authentic self — the parent reflected back only certain aspects, leading the child to believe that their true self was somehow deficient or unacceptable" }, { letter: "C", text: "Physical neglect" }, { letter: "D", text: "Overly strict boundaries" }], answer: "B", explanation: "The Four's wound is a mirroring wound: the parent failed to see and reflect the child's full self. What was reflected back was partial or distorted, creating the lifelong sense that something essential about them was missed or rejected." },
  { id: 814, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Object Relations Deep", question: "The Four's relationship to Klein's 'depressive position' is:", options: [{ letter: "A", text: "Irrelevant" }, { letter: "B", text: "They remain stuck in it — the awareness that good and bad coexist in the same object creates the bittersweet quality of all Four experience, where nothing is simply good or simply bad" }, { letter: "C", text: "They skip it entirely" }, { letter: "D", text: "They reach it faster than others" }], answer: "B", explanation: "Klein's depressive position involves accepting ambivalence: the loved object is also the frustrating object. Fours live in this complexity permanently — everything is bittersweet because they're acutely aware of the dark side of every light, and vice versa." },
  { id: 815, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Counter-Instinctual Combos", question: "Why is the SP4 considered the most counter-instinctual Four?", options: [{ letter: "A", text: "They're the most dramatic" }, { letter: "B", text: "While Fours typically express suffering outwardly, SP4s internalize it — they suffer in silence, endure without complaining, and may even appear tough or stoic, hiding their emotional intensity behind a wall of resilience" }, { letter: "C", text: "They don't feel emotions" }, { letter: "D", text: "They're the happiest" }], answer: "B", explanation: "SP4s flip the Four script: instead of expressing pain, they endure it silently. Naranjo called them 'tenacious' — they bear suffering stoically, which can look like One-ish discipline or Five-ish withdrawal. Their envy manifests as self-demand rather than self-pity." },
  { id: 816, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Counter-Instinctual Combos", question: "The Social Four (SO4) experiences envy primarily as:", options: [{ letter: "A", text: "Individual competition" }, { letter: "B", text: "Feeling like an outsider in every group — belonging to the group while simultaneously feeling they don't truly fit, creating a shame-based relationship with social connection" }, { letter: "C", text: "Not experiencing envy at all" }, { letter: "D", text: "Envy of material wealth" }], answer: "B", explanation: "SO4s focus their envy on belonging itself: others seem to fit in naturally, while they feel permanently on the outside looking in. Their shame is social — 'There's something wrong with me that prevents real belonging.'" },
  { id: 817, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Historical Enneagram", question: "In Riso and Hudson's Levels of Development, a healthy Level 1-3 Four manifests as:", options: [{ letter: "A", text: "More dramatic and expressive" }, { letter: "B", text: "Profoundly creative and self-renewing — able to transform personal suffering into universal beauty, creating art and connection that speaks to the human condition" }, { letter: "C", text: "Emotionally numb" }, { letter: "D", text: "Highly competitive" }], answer: "B", explanation: "Healthy Fours are among the most creative humans alive. They've learned to channel their depth into universal expression — their personal pain becomes the raw material for art, therapy, or connection that touches others at the deepest level." },
  { id: 818, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Historical Enneagram", question: "The romantic movement in art (19th century) most closely aligns with which Enneagram type?", options: [{ letter: "A", text: "Type 3" }, { letter: "B", text: "Type 4 — the elevation of individual feeling, the beauty of melancholy, the artist as tortured genius, and nature as a mirror for inner emotional states" }, { letter: "C", text: "Type 8" }, { letter: "D", text: "Type 1" }], answer: "B", explanation: "Romanticism IS Four culture: the belief that emotion is truth, that suffering produces beauty, that the individual's inner world is the most important reality, and that art should express the depths of personal experience. Keats, Shelley, Byron — all Four energy." },
  { id: 819, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Integration/Disintegration Chains", question: "When a Four disintegrates to Two and then further degrades, what emerges?", options: [{ letter: "A", text: "Healthy self-care" }, { letter: "B", text: "Desperate, clingy neediness — the Four abandons their independence entirely, becoming possessive, manipulative through emotional need, and unable to function without external validation" }, { letter: "C", text: "Intellectual detachment" }, { letter: "D", text: "Explosive anger" }], answer: "B", explanation: "Deep Four disintegration via Two looks like emotional vampirism: the independent, creative Four becomes desperately dependent, using emotional crises to keep others close, and losing all sense of self without constant external validation." },
  { id: 820, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Integration/Disintegration Chains", question: "When a Four integrates to One, the transformation specifically involves:", options: [{ letter: "A", text: "Becoming judgmental" }, { letter: "B", text: "Adding structure and discipline to creativity — the feelings find form, the longing becomes action, and the Four discovers that consistent effort creates more authentic expression than waiting for inspiration" }, { letter: "C", text: "Suppressing all emotions" }, { letter: "D", text: "Following rules blindly" }], answer: "B", explanation: "One-integration gives Fours what they most need: a framework for their feelings. Instead of drowning in emotion, they channel it. Instead of waiting for the perfect mood, they show up daily. The result is art and life that's both deeply felt and well-crafted." },
  { id: 821, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Naranjo's Character Types", question: "Naranjo identified that Fours often confuse authenticity with:", options: [{ letter: "A", text: "Happiness" }, { letter: "B", text: "Emotional intensity — they believe that the strongest feeling is the most true, when in fact authentic experience often includes quiet, simple, or ordinary states" }, { letter: "C", text: "Logic" }, { letter: "D", text: "Physical sensation" }], answer: "B", explanation: "Naranjo noticed that Fours equate intensity with truth: 'The more I feel, the more real I am.' This creates a bias where dramatic emotions feel authentic and quiet contentment feels fake — a fundamental perceptual error that maintains their suffering." },
  { id: 822, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Differential Diagnosis", question: "A person oscillates between grandiosity and worthlessness. This could be a Four or a narcissistic personality. The differentiator is:", options: [{ letter: "A", text: "They're the same thing" }, { letter: "B", text: "Fours have genuine empathy and can tolerate others' success without feeling threatened — their shame is about identity, not about controlling others' perceptions" }, { letter: "C", text: "Fours are always grandiose" }, { letter: "D", text: "Narcissists are always worthless" }], answer: "B", explanation: "Both experience the swing between 'I'm special' and 'I'm worthless,' but Fours maintain genuine empathy and don't exploit others for narcissistic supply. The Four's specialness-seeking is about identity, not interpersonal control." },
  { id: 823, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Shadow Work", question: "The Four's 'envy of ordinariness' refers to:", options: [{ letter: "A", text: "Wanting ordinary things" }, { letter: "B", text: "The hidden desire to simply be happy, content, and at ease — envying others' ability to enjoy life without the constant overlay of melancholy and longing that the Four can't switch off" }, { letter: "C", text: "Being boring" }, { letter: "D", text: "Wanting to be average" }], answer: "B", explanation: "Beneath the Four's disdain for the ordinary lies a desperate wish: 'I wish I could just be happy like them.' The envy of others' ease is the Four's deepest shadow — admitting it means admitting their uniqueness might be a prison, not a gift." },
  { id: 824, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Growth Practices", question: "Somatic practices (yoga, breathwork, dance) benefit Fours because:", options: [{ letter: "A", text: "They're trendy" }, { letter: "B", text: "They interrupt the Four's tendency to live in emotional narrative and bring attention to the body's present-moment experience — where feelings exist without stories attached" }, { letter: "C", text: "They build physical strength" }, { letter: "D", text: "They provide social connection" }], answer: "B", explanation: "Fours live in emotional stories: 'I'm sad because...' Somatic work teaches them to feel without narrating — to experience the sensation of sadness in the body without the elaborate story of why they're special for feeling it." },
  { id: 825, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Tritype Deep Dives", question: "The 479 tritype ('The Gentle Spirit') creates what kind of Four?", options: [{ letter: "A", text: "The most aggressive Four" }, { letter: "B", text: "A dreamy, imaginative, conflict-averse Four who uses creativity and positivity to maintain their sense of specialness while avoiding pain" }, { letter: "C", text: "A highly ambitious Four" }, { letter: "D", text: "A completely detached Four" }], answer: "B", explanation: "The 479 softens the Four's intensity with Seven's optimism and Nine's peacemaking. This creates a gentle, imaginative Four who seeks specialness through creativity and vision rather than through suffering — the Four most likely to be mistyped as a Nine or Seven." },
  { id: 826, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Spiritual Traditions", question: "The Four's spiritual practice of 'objective self-observation' is difficult because:", options: [{ letter: "A", text: "They can't concentrate" }, { letter: "B", text: "Every attempt to observe themselves gets hijacked by identification with the emotional content — they can't watch their sadness without becoming their sadness" }, { letter: "C", text: "They're already too self-aware" }, { letter: "D", text: "They don't like meditation" }], answer: "B", explanation: "Self-observation requires detachment from what's observed. Fours fuse with their emotions so completely that observing sadness BECOMES being sad. The witness dissolves into the witnessed, making the disidentification that growth requires extremely challenging." },
  { id: 827, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Attachment Style", question: "The Four's 'approach-avoidance' pattern in relationships mirrors which psychological concept?", options: [{ letter: "A", text: "Operant conditioning" }, { letter: "B", text: "The 'hedgehog's dilemma' — the closer they get, the more they fear being hurt or losing their uniqueness through merger, so they retreat; but distance brings the agony of longing" }, { letter: "C", text: "Classical conditioning" }, { letter: "D", text: "Learned helplessness" }], answer: "B", explanation: "Schopenhauer's hedgehog dilemma perfectly describes the Four in love: cold alone (longing), burned by closeness (loss of self). They oscillate between craving intimacy and needing distance, never quite finding the temperature that's 'right.'" },
  { id: 828, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Communication Style", question: "Fours in therapy often display 'resistance through emotional expression,' meaning:", options: [{ letter: "A", text: "They refuse to talk" }, { letter: "B", text: "They express so much emotion so eloquently that the session stays at the surface of feeling without reaching the structural patterns underneath — emotion itself becomes a defense" }, { letter: "C", text: "They argue with the therapist" }, { letter: "D", text: "They intellectualize everything" }], answer: "B", explanation: "Paradoxically, Fours can use emotional expression to avoid deeper work. Beautifully articulated suffering can substitute for actual transformation. A skilled therapist will notice: 'You're performing your pain rather than working through it.'" },
  { id: 829, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Coping Under Stress", question: "The Four's 'artistic crisis' typically involves:", options: [{ letter: "A", text: "Running out of supplies" }, { letter: "B", text: "The terrifying realization that their art may be a refined form of their fixation — that their 'authentic expression' is actually a sophisticated performance of suffering, not genuine creativity" }, { letter: "C", text: "Writer's block only" }, { letter: "D", text: "Competition anxiety" }], answer: "B", explanation: "The deepest Four crisis isn't creative block — it's questioning whether their creativity was ever authentic. Was the art real expression, or was it just the fixation wearing a beautiful mask? This meta-crisis can either destroy or transform their creative identity." },
  { id: 830, type: 4, difficulty: 4 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Parenting Style", question: "The greatest gift Four parents give their children is:", options: [{ letter: "A", text: "Material comfort" }, { letter: "B", text: "Permission to feel the full spectrum of human emotion — including the dark, confusing, and painful parts that other parents might try to fix or dismiss" }, { letter: "C", text: "Academic pressure" }, { letter: "D", text: "Social connections" }], answer: "B", explanation: "Four parents normalize emotional complexity. Their children grow up knowing that sadness, anger, confusion, and grief are valid and nameable. In a culture that pressure-washes emotions into 'fine,' Four parents create emotionally literate children." },
  // ── DIFFICULTY 5 (20 questions) ──
  { id: 831, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 41, track2Day: 91, category: "Ichazo Fixations", question: "Ichazo's concept of the Four's 'trap' is 'authenticity.' What does this mean?", options: [{ letter: "A", text: "Authenticity is always good" }, { letter: "B", text: "The Four believes that if they can just be authentic enough, they'll find what they're missing — but the pursuit of authenticity becomes its own performance, and 'being authentic' replaces actually being" }, { letter: "C", text: "They should be less authentic" }, { letter: "D", text: "Authenticity is their strength" }], answer: "B", explanation: "The trap is the strategy that seems like growth but deepens the fixation. For Fours, pursuing authenticity can become another performance: 'I'm being authentically sad' is still a performance of sadness. True authenticity would include ordinary, boring, uncomplicated moments." },
  { id: 832, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 42, track2Day: 92, category: "Ichazo Fixations", question: "The Four's virtue is 'Equanimity' (or 'Emotional Balance'). This means:", options: [{ letter: "A", text: "Suppressing all emotions" }, { letter: "B", text: "The ability to experience all emotional states — including positive and ordinary ones — with equal presence, without amplifying suffering or diminishing joy" }, { letter: "C", text: "Being emotionally flat" }, { letter: "D", text: "Always being happy" }], answer: "B", explanation: "Equanimity doesn't mean the Four stops feeling deeply — it means they stop privileging suffering over joy. They can be fully present to contentment without mistrusting it, and fully present to pain without inflating it. All emotions get equal airtime." },
  { id: 833, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 43, track2Day: 93, category: "Object Relations Deep", question: "The Four's relationship to Fairbairn's concept of the 'internal saboteur' is:", options: [{ letter: "A", text: "Irrelevant" }, { letter: "B", text: "The Four's internal saboteur is particularly active — it attacks any movement toward happiness or wholeness, because the internal system has organized around lack, and completeness would collapse the identity structure" }, { letter: "C", text: "Fours don't self-sabotage" }, { letter: "D", text: "It only applies to Type 6" }], answer: "B", explanation: "Fairbairn's internal saboteur — the part that attacks the self when approaching health — is hyperactive in Fours. Just as they near happiness, something inside whispers: 'This isn't real,' 'You don't deserve this,' or 'Something's missing.' The saboteur preserves the familiar pain." },
  { id: 834, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 44, track2Day: 94, category: "Counter-Instinctual Combos", question: "An SP4 with a 3-wing (SP 4w3) creates what unique presentation?", options: [{ letter: "A", text: "The stereotypical dramatic Four" }, { letter: "B", text: "A hardworking, ambitious person who suffers silently — they look like achievers but are driven by internal pain rather than image, often confused with Type 1, 3, or 6" }, { letter: "C", text: "A purely emotional person" }, { letter: "D", text: "A social butterfly" }], answer: "B", explanation: "SP 4w3 is a remarkable disguise: the SP counter-type's stoic endurance combined with the 3-wing's competence creates someone who channels suffering into achievement. They look successful and put-together while internally experiencing the full Four emotional depth." },
  { id: 835, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 45, track2Day: 95, category: "Counter-Instinctual Combos", question: "An SX4 with a 5-wing (SX 4w5) is often confused with Type 8 because:", options: [{ letter: "A", text: "They look identical" }, { letter: "B", text: "The sexual instinct's intensity plus the Five's penetrating focus creates a fiercely independent, bluntly honest person who demands authenticity with aggressive force — their envy becomes competitive rage" }, { letter: "C", text: "They're physically large" }, { letter: "D", text: "They like power" }], answer: "B", explanation: "SX 4w5 is the most intense Four variant: sexually driven intensity (demanding, competitive) + Five-wing's dark intellectualism = a person who can feel like an Eight in their forceful demand for truth. But underneath the aggression is the Four's core wound of deficiency." },
  { id: 836, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 46, track2Day: 96, category: "Historical Enneagram", question: "The Enneagram of Process positions the Four between Three and Five. What does this reveal?", options: [{ letter: "A", text: "Nothing significant" }, { letter: "B", text: "The Four is caught between the Three's drive to be seen and the Five's desire to withdraw — they want to be visible but only in their authentic depth, not as a performance" }, { letter: "C", text: "They should become a 3 or 5" }, { letter: "D", text: "It's numerologically random" }], answer: "B", explanation: "The Four's position between Three and Five mirrors their core tension: wing toward Three and they risk performing their emotions for an audience; wing toward Five and they risk disappearing into private suffering. Both wings offer different escapes from the Four's central wound." },
  { id: 837, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 47, track2Day: 97, category: "Integration/Disintegration Chains", question: "The complete Four growth trajectory (4→1→7) reveals:", options: [{ letter: "A", text: "Random connections" }, { letter: "B", text: "A path from emotional depth (4) through disciplined action (1) to genuine joy and freedom (7) — the Four learns first to structure their feelings, then to truly enjoy life without qualifications" }, { letter: "C", text: "Only one step of growth" }, { letter: "D", text: "A path toward more suffering" }], answer: "B", explanation: "The 4→1→7 trajectory is beautiful: raw emotion gains structure (1), and structured emotion gains lightness (7). The Four who has done deep growth can access genuine, uncomplicated joy — the very thing they once believed was impossible for them." },
  { id: 838, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 48, track2Day: 98, category: "Panel Wisdom", question: "The most healing thing Fours report hearing from another Four is:", options: [{ letter: "A", text: "You're so unique" }, { letter: "B", text: "I feel exactly the same way — and the realization that their 'unique' suffering is universal paradoxically frees them from the prison of specialness" }, { letter: "C", text: "You should feel better" }, { letter: "D", text: "You're overreacting" }], answer: "B", explanation: "The Four's liberation begins when they discover their suffering isn't unique. Hearing 'me too' from another Four shatters the specialness narrative — and in its place, something better emerges: genuine connection through shared human experience rather than isolated uniqueness." },
  { id: 839, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 49, track2Day: 99, category: "Differential Diagnosis", question: "A person alternates between creative brilliance and paralytic depression. Could be Four or bipolar. How to distinguish?", options: [{ letter: "A", text: "They're the same thing" }, { letter: "B", text: "Four's emotional cycles are psychologically coherent — they respond to meaning, identity, and relationship triggers; bipolar cycling is neurochemical and can occur without psychological trigger" }, { letter: "C", text: "Fours are never bipolar" }, { letter: "D", text: "Only medication can tell" }], answer: "B", explanation: "A Four's emotional intensity has narrative logic: the despair follows rejection, the creativity follows inspiration. Bipolar episodes can arrive without precipitant. Of course, a person can be both Four AND bipolar — the distinction is in the pattern, not an either/or." },
  { id: 840, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 50, track2Day: 100, category: "Shadow Work", question: "The Four's ultimate shadow work involves recognizing:", options: [{ letter: "A", text: "That they need more drama" }, { letter: "B", text: "That their identity as 'the deep one who suffers beautifully' is itself a performance — and that letting go of this identity doesn't mean becoming shallow, but discovering a depth that doesn't require suffering to prove it" }, { letter: "C", text: "That they should suppress feelings" }, { letter: "D", text: "That other types are shallow" }], answer: "B", explanation: "The Four's deepest work is recognizing that depth without suffering is possible. They can be profound, creative, and emotionally rich without the melancholy undertow. True depth doesn't need pain as proof — it exists naturally when the fixation loosens its grip." },
  { id: 841, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 1, track2Day: 51, category: "Naranjo's Character Types", question: "Naranjo described the Four's 'envy' as fundamentally different from ordinary jealousy because:", options: [{ letter: "A", text: "It's weaker" }, { letter: "B", text: "It's ontological — not 'I want what you have' but 'I want to BE what you are' — the Four envies others' very being, their ease of existence, not their possessions" }, { letter: "C", text: "It's about money" }, { letter: "D", text: "It only appears in childhood" }], answer: "B", explanation: "Naranjo distinguished the Four's envy from garden-variety jealousy: it's not about objects but about being. The Four doesn't want your car — they want your ability to simply exist without the constant undertow of feeling deficient. It's an envy of essence." },
  { id: 842, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 2, track2Day: 52, category: "Growth Practices", question: "The practice of 'doing something ordinary and finding it enough' is the Four's equivalent of:", options: [{ letter: "A", text: "Busywork" }, { letter: "B", text: "A Zen koan — it confronts the fixation directly by demonstrating that the ordinary moment contains everything they've been longing for, if they can stop reaching past it" }, { letter: "C", text: "Procrastination" }, { letter: "D", text: "Settling for less" }], answer: "B", explanation: "Making breakfast. Folding laundry. Walking without headphones. These ordinary acts become profound practice for Fours — each one a chance to discover that this moment, without drama or significance, is complete. The ordinary is the spiritual frontier the Four must explore." },
  { id: 843, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 3, track2Day: 53, category: "Tritype Deep Dives", question: "The 415 tritype vs. the 461 tritype: what's the core difference?", options: [{ letter: "A", text: "They're identical" }, { letter: "B", text: "The 415 channels Four-ness through intellectual investigation (5) with ethical grounding (1), creating a philosophical type; the 461 channels it through principled action (1) with anxious loyalty (6), creating a reform-oriented type" }, { letter: "C", text: "One is creative, the other isn't" }, { letter: "D", text: "They have the same behavior" }], answer: "B", explanation: "Same core type (4), very different expressions. The 415 is the brooding intellectual — think Kierkegaard. The 461 is the principled reformer — think someone who channels their personal pain into social justice. The supporting types reshape how the Four's depth gets expressed." },
  { id: 844, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 4, track2Day: 54, category: "Spiritual Traditions", question: "The Christian mystical tradition of 'dark night of the soul' resonates with Fours but also challenges them because:", options: [{ letter: "A", text: "It's too religious" }, { letter: "B", text: "Fours romanticize the darkness while the tradition teaches that the dark night is a process to move through, not an identity to adopt — God strips away attachments including the attachment to suffering" }, { letter: "C", text: "It's too simple" }, { letter: "D", text: "It doesn't involve emotions" }], answer: "B", explanation: "St. John of the Cross described the dark night as a purgation — a temporary passage, not a permanent home. Fours tend to set up camp in the darkness, decorating it beautifully. The tradition insists: keep walking. The darkness is a doorway, not a destination." },
  { id: 845, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 5, track2Day: 55, category: "Historical Enneagram", question: "Søren Kierkegaard is often typed as a Four. His concept of 'the aesthetic stage' relates to the Four fixation because:", options: [{ letter: "A", text: "He liked art" }, { letter: "B", text: "The aesthetic stage describes living for emotional experience and personal meaning without ethical commitment — the Four's tendency to live in feeling without grounding in action or responsibility" }, { letter: "C", text: "He was a painter" }, { letter: "D", text: "He was melancholy sometimes" }], answer: "B", explanation: "Kierkegaard's aesthetic stage perfectly describes unhealthy Four: pursuing intense experience for its own sake, using emotion as a way to avoid commitment, and treating life as an art project rather than a moral engagement. His 'ethical stage' corresponds to One-integration." },
  { id: 846, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 6, track2Day: 56, category: "Instinct x Wing Combos", question: "Rank the six Four subtypes from most to least 'typically Four':", options: [{ letter: "A", text: "All look the same" }, { letter: "B", text: "SX 4w3 (most dramatic) → SO 4w3 → SX 4w5 → SO 4w5 → SP 4w3 → SP 4w5 (least recognizable)" }, { letter: "C", text: "SP 4w5 is the most dramatic" }, { letter: "D", text: "Rankings don't apply" }], answer: "B", explanation: "SX + 3-wing maximizes the Four's external expression: dramatic, competitive, expressive, attention-seeking. SP + 5-wing minimizes it: stoic, intellectual, withdrawn, barely recognizable as a Four. The range is enormous — from Frida Kahlo to a quiet librarian." },
  { id: 847, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 7, track2Day: 57, category: "Panel Wisdom", question: "Experienced Enneagram teachers note that the Four's greatest contribution to the Enneagram community is:", options: [{ letter: "A", text: "Their organizational skills" }, { letter: "B", text: "Their insistence on emotional truth — they hold the space for depth and authenticity that prevents the system from becoming merely intellectual or self-improvement-oriented" }, { letter: "C", text: "Their punctuality" }, { letter: "D", text: "Their leadership" }], answer: "B", explanation: "Fours are the conscience of the Enneagram community. When the system risks becoming a productivity tool or party trick, Fours insist on its depth: 'This is about the human soul, not a personality quiz.' Their emotional guardianship keeps the work honest." },
  { id: 848, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 8, track2Day: 58, category: "Differential Diagnosis", question: "A creative person with intense shame, emotional volatility, and relationship instability could be a Four or have BPD. The key difference is:", options: [{ letter: "A", text: "They're the same" }, { letter: "B", text: "Four's identity disturbance has a coherent theme (uniqueness/deficiency); BPD's identity disturbance is more chaotic and fragmented. Fours have a consistent sense of who they are (even if it's painful); BPD involves a more fundamental lack of stable self-structure" }, { letter: "C", text: "Fours never have BPD" }, { letter: "D", text: "BPD is just another word for Type 4" }], answer: "B", explanation: "Both involve emotional intensity and identity issues, but Fours have a stable (if painful) self-narrative: 'I am the unique, deep one who suffers.' BPD involves more fundamental identity fragmentation without this narrative coherence. And again — a person can be both." },
  { id: 849, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 9, track2Day: 59, category: "Growth Practices", question: "Why is 'helping others without making it about your own emotional journey' transformative for Fours?", options: [{ letter: "A", text: "It distracts them" }, { letter: "B", text: "It breaks the self-referential loop — for once, someone else's experience takes center stage, and the Four discovers that their identity survives not being the protagonist" }, { letter: "C", text: "It's not transformative" }, { letter: "D", text: "It builds their resume" }], answer: "B", explanation: "Fours live in a self-referential universe where everything loops back to 'how does this relate to my inner world?' Service to others — genuine, ego-free service — breaks this loop and reveals that the self doesn't collapse when it's not the center of attention." },
  { id: 850, type: 4, difficulty: 5 as 1|2|3|4|5, track1Day: 10, track2Day: 60, category: "Naranjo's Character Types", question: "Naranjo's ultimate insight about the Four's transformation is:", options: [{ letter: "A", text: "They need to stop feeling" }, { letter: "B", text: "The Four must discover that what they've been seeking through longing and uniqueness was always already present — the missing piece was never actually missing, it was hidden by the very act of searching for it" }, { letter: "C", text: "They need more therapy" }, { letter: "D", text: "They should become Threes" }], answer: "B", explanation: "The paradox of the Four's journey: the longing for what's missing creates the experience of something missing. The origin (Holy Origin) was never lost. When the Four stops seeking, they find. When they stop longing, they arrive. The missing piece was the looking itself." },
];
